// Filtra por semana actual (lunes a domingo) y agrupa el conteo por materia
function getInicioSemana(date) {
  const d = new Date(date);
  const day = d.getDay(); // 0 = domingo
  const diff = d.getDate() - day + (day === 0 ? -6 : 1);
  const lunes = new Date(d.setDate(diff));
  lunes.setHours(0, 0, 0, 0);
  return lunes;
}

const hoy = new Date();
const inicioSemana = getInicioSemana(new Date(hoy));
const finSemana = new Date(inicioSemana);
finSemana.setDate(finSemana.getDate() + 6);
finSemana.setHours(23, 59, 59, 999);

const conteos = {};
let total = 0;

for (const item of $input.all()) {
  const row = item.json;

  // Ajusta los nombres de columna si en tu hoja se llaman distinto
  const fechaRaw = row.fecha || row.Fecha || row.FECHA;
  if (!fechaRaw) continue;

  const fecha = new Date(fechaRaw);
  if (isNaN(fecha.getTime())) continue;
  if (fecha < inicioSemana || fecha > finSemana) continue;

  const materia = String(row.materia || row.Materia || row.MATERIA || 'Sin materia').trim();
  conteos[materia] = (conteos[materia] || 0) + 1;
  total++;
}

return [{
  json: {
    conteos,
    total,
    inicioSemana: inicioSemana.toISOString().slice(0, 10),
    finSemana: finSemana.toISOString().slice(0, 10)
  }
}];

const data = $input.first().json;
const c = data.conteos;

const matematicas = c['Matemáticas'] || c['Matematicas'] || 0;
const programacion = c['Programación'] || c['Programacion'] || 0;
const quimica = c['Química'] || c['Quimica'] || 0;

// Materias que llegan de la hoja pero no están en el formato fijo del examen
const fijas = ['Matemáticas','Matematicas','Programación','Programacion','Química','Quimica'];
const otras = Object.keys(c).filter(m => !fijas.includes(m));
let extra = '';
for (const m of otras) {
  extra += `\n📌 ${m}: ${c[m]}`;
}

const mensaje =
`📚 Resumen de Tutorías por Materia\n` +
`----------------------------\n` +
`🧮 Matemáticas: ${matematicas}\n` +
`💻 Programación: ${programacion}\n` +
`🧪 Química: ${quimica}${extra}\n\n` +
`📈 TOTAL SEMANA: ${data.total}\n` +
`(Semana del ${data.inicioSemana} al ${data.finSemana})`;

return [{ json: { mensaje } }];

const hoy = new Date();
const diaSemana = hoy.getDay();
const diferenciaLunes = hoy.getDate() - (diaSemana === 0 ? 6 : diaSemana - 1);
const lunesActual = new Date(hoy.setDate(diferenciaLunes));
lunesActual.setHours(0, 0, 0, 0);
const domingoActual = new Date(lunesActual);
domingoActual.setDate(lunesActual.getDate() + 6);
domingoActual.setHours(23, 59, 59, 999);

function parsearFecha(fechaStr) {
  if (!fechaStr) return null;
  if (fechaStr.includes('/')) {
    const [dia, mes, anio] = fechaStr.split('/');
    return new Date(anio, mes - 1, dia);
  }
  return new Date(fechaStr);
}

const registros = items.map(item => item.json);
const registrosSemana = registros.filter(reg => {
  const fechaReg = parsearFecha(reg.Fecha);
  return fechaReg && fechaReg >= lunesActual && fechaReg <= domingoActual;
});

const conteoMaterias = {};
let totalSemana = 0;

registrosSemana.forEach(reg => {
  const materia = reg.materia ? reg.materia.trim() : "Sin Especificar";
  conteoMaterias[materia] = (conteoMaterias[materia] || 0) + 1;
  totalSemana++;
});

let cuerpoMensaje = "";
const materiasRequeridas = ["Matemáticas", "Programación", "Química"];

materiasRequeridas.forEach(materia => {
  const cantidad = conteoMaterias[materia] || 0;
  cuerpoMensaje += `${materia}: ${cantidad}\n\n`;
});

Object.keys(conteoMaterias).forEach(materia => {
  if (!materiasRequeridas.includes(materia)) {
    cuerpoMensaje += `${materia}: ${conteoMaterias[materia]}\n\n`;
  }
});

const mensajeTelegram = `Resumen de Tutorias por Materia\n\n----------------------------\n\n${cuerpoMensaje}TOTAL SEMANA: ${totalSemana}`;

return [{ json: { mensajeTelegram } }];
